// inferred-not-tested:default export = NightingaleTrack 类;需消费方注册 custom element
import NightingaleTrack from 'https://cdn.jsdelivr.net/npm/@nightingale-elements/nightingale-track@5.6.0/+esm';
if (!customElements.get('nightingale-track')) customElements.define('nightingale-track', NightingaleTrack);
const track = document.createElement('nightingale-track');
track.setAttribute('length', String(data.length));
track.setAttribute('display-start', String(data.displayStart ?? 1));
track.setAttribute('display-end', String(data.displayEnd ?? data.length));
track.setAttribute('height', String(data.height ?? 100));
if (data.layout) track.setAttribute('layout', data.layout);
document.getElementById('track').appendChild(track);
customElements.whenDefined('nightingale-track').then(() => { track.data = data.features; });

